using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsProperties()
        {
            var items = new List<int> { 1, 2, 3 };

            var list = new PaginatedList<int>(items, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
            Assert.Equal(4, list.TotalPages); // ceil(10/3)
            Assert.Equal(3, list.Count);
        }

        [Fact]
        public void HasPreviousPage_TrueWhenNotFirstPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 3);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_FalseWhenFirstPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 3);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_TrueWhenNotLastPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 3);
            Assert.True(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_FalseWhenLastPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 4, 3);
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(2, result.PageIndex);
            Assert.Equal(4, result.TotalPages);
            Assert.Equal(5, result.Count);
            Assert.Equal(6, result.First());
        }

        [Fact]
        public void Create_FirstPage()
        {
            var source = Enumerable.Range(1, 10).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 3);

            Assert.Equal(1, result.PageIndex);
            Assert.Equal(new[] { 1, 2, 3 }, result.ToArray());
        }

        [Fact]
        public void Create_LastPage_PartialItems()
        {
            var source = Enumerable.Range(1, 7).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 3);

            Assert.Equal(3, result.PageIndex);
            Assert.Single(result); // only item 7
            Assert.Equal(7, result.First());
        }

        [Fact]
        public void TotalPages_SinglePage_WhenExact()
        {
            var list = new PaginatedList<int>(new List<int>(), 5, 1, 5);
            Assert.Equal(1, list.TotalPages);
        }
    }
}

using System;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests
{
    public static class TestHelper
    {
        public static SchoolContext CreateContext(string? dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(dbName)
                .Options;
            return new SchoolContext(options);
        }

        public static SchoolContext CreateSeededContext(string? dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var context = CreateContext(dbName);
            SeedData(context);
            return context;
        }

        public static void SeedData(SchoolContext context)
        {
            var instructor1 = new Instructor
            {
                ID = 1,
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = DateTime.Parse("1995-03-11")
            };
            var instructor2 = new Instructor
            {
                ID = 2,
                FirstMidName = "Fadi",
                LastName = "Fakhouri",
                HireDate = DateTime.Parse("2002-07-06")
            };

            context.Instructors.AddRange(instructor1, instructor2);
            context.SaveChanges();

            var dept1 = new Department
            {
                DepartmentID = 1,
                Name = "English",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 1
            };
            var dept2 = new Department
            {
                DepartmentID = 2,
                Name = "Mathematics",
                Budget = 100000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 2
            };

            context.Departments.AddRange(dept1, dept2);
            context.SaveChanges();

            var course1 = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };
            var course2 = new Course
            {
                CourseID = 4022,
                Title = "Microeconomics",
                Credits = 3,
                DepartmentID = 2
            };

            context.Courses.AddRange(course1, course2);
            context.SaveChanges();

            var student1 = new Student
            {
                ID = 10,
                FirstMidName = "Carson",
                LastName = "Alexander",
                EnrollmentDate = DateTime.Parse("2010-09-01")
            };
            var student2 = new Student
            {
                ID = 11,
                FirstMidName = "Meredith",
                LastName = "Alonso",
                EnrollmentDate = DateTime.Parse("2012-09-01")
            };

            context.Students.AddRange(student1, student2);
            context.SaveChanges();

            context.Enrollments.Add(new Enrollment
            {
                EnrollmentID = 1,
                StudentID = 10,
                CourseID = 1050,
                Grade = Grade.A
            });
            context.SaveChanges();

            context.CourseAssignments.Add(new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 1050
            });
            context.SaveChanges();

            context.OfficeAssignments.Add(new OfficeAssignment
            {
                InstructorID = 2,
                Location = "Smith 17"
            });
            context.SaveChanges();
        }
    }
}

