            context.SaveChanges();

            var dept = new Department
            {
                Name = "Science",
                Budget = 100000,
                StartDate = DateTime.Parse("2020-01-01"),
                InstructorID = instructor.ID
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            var retrieved = context.Departments
                .Include(d => d.Administrator)
                .Single();
