{"path": "/tmp/sv-78f05e5366ab443c9e9c83fcce39ddb4/ContosoUniversity.Tests/Models/PaginatedListTests.cs", "file_text": "using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsProperties()
        {
            var items = new List<int> { 1, 2, 3 };

            var list = new PaginatedList<int>(items, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
            Assert.Equal(4, list.TotalPages); // ceil(10/3)
            Assert.Equal(3, list.Count);
        }

        [Fact]
        public void HasPreviousPage_TrueWhenNotFirstPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 3);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_FalseWhenFirstPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 3);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_TrueWhenNotLastPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 3);
            Assert.True(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_FalseWhenLastPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 4, 3);
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(2, result.PageIndex);
            Assert.Equal(4, result.TotalPages);
            Assert.Equal(5, result.Count);
            Assert.Equal(6, result.First());
        }

        [Fact]
        public void Create_FirstPage()
        {
            var source = Enumerable.Range(1, 10).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 3);

            Assert.Equal(1, result.PageIndex);
            Assert.Equal(new[] { 1, 2, 3 }, result.ToArray());
        }

        [Fact]
        public void Create_LastPage_PartialItems()
        {
            var source = Enumerable.Range(1, 7).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 3);

            Assert.Equal(3, result.PageIndex);
            Assert.Single(result); // only item 7
            Assert.Equal(7, result.First());
        }

        [Fact]
        public void TotalPages_SinglePage_WhenExact()
        {
            var list = new PaginatedList<int>(new List<int>(), 5, 1, 5);
            Assert.Equal(1, list.TotalPages);
        }
    }
}
"}

