using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestHelper.CreateSeededContext();
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewWithInstructorIndexData()
        {
            var result = _controller.Index(null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            var result = _controller.Index(1, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
        }

        [Fact]
        public void Details_ReturnsInstructor()
        {
            var result = _controller.Details(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var instructor = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal("Abercrombie", instructor.LastName);
        }

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenInstructorMissing()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithInstructor()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var instructor = Assert.IsType<Instructor>(viewResult.Model);
            Assert.NotNull(instructor.CourseAssignments);
            Assert.Empty(instructor.CourseAssignments);
        }

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01")
            };

            var result = _controller.Create(instructor, null!);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Equal(3, _context.Instructors.Count());
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01")
            };

            var result = _controller.Create(instructor, new[] { "1050" });

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);

            var savedInstructor = _context.Instructors
                .Where(i => i.LastName == "Instructor")
                .Single();
            var assignments = _context.CourseAssignments
                .Where(ca => ca.InstructorID == savedInstructor.ID)
                .ToList();
            Assert.Single(assignments);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor();

            var result = _controller.Create(instructor, null!);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Delete_Get_ReturnsInstructor()
        {
            var result = _controller.Delete(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var instructor = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal("Abercrombie", instructor.LastName);
        }

        [Fact]
        public void Delete_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsNotFound_WhenInstructorMissing()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            // Instructor 2 has office assignment, use them to test cascade behavior
            var result = _controller.DeleteConfirmed(2);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Single(_context.Instructors);
        }

        [Fact]
        public void DeleteConfirmed_ClearsDepartmentAdministrator()
        {
            // Instructor 1 is administrator of department 1
            _controller.DeleteConfirmed(1);

            var dept = _context.Departments.Find(1)!;
            Assert.Null(dept.InstructorID);
        }
    }
}

