using System;
using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests
    {
        [Fact]
        public void CanCreateDatabase()
        {
            using var context = TestHelper.CreateContext();

            Assert.True(context.Database.EnsureCreated());
        }

        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            using var context = TestHelper.CreateContext();

            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2020-01-01")
            };
            context.Students.Add(student);
            context.SaveChanges();

            var retrieved = context.Students.Single();
            Assert.Equal("Student", retrieved.LastName);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            using var context = TestHelper.CreateContext();

            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Teacher",
                HireDate = DateTime.Parse("2020-01-01")
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            var retrieved = context.Instructors.Single();
            Assert.Equal("Teacher", retrieved.LastName);
        }

        [Fact]
        public void CanAddDepartmentWithAdministrator()
        {
            using var context = TestHelper.CreateContext();

            var instructor = new Instructor
            {
                FirstMidName = "Admin",
                LastName = "Prof",
                HireDate = DateTime.Parse("2020-01-01")
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            var dept = new Department
            {
                Name = "Science",
                Budget = 100000,
                StartDate = DateTime.Parse("2020-01-01"),
                InstructorID = instructor.ID
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            var retrieved = context.Departments
                .Include(d => d.Administrator)
                .Single();
            Assert.Equal("Science", retrieved.Name);
            Assert.NotNull(retrieved.Administrator);
            Assert.Equal("Prof", retrieved.Administrator!.LastName);
        }

        [Fact]
        public void CanAddCourseWithDepartment()
        {
            using var context = TestHelper.CreateContext();

            var dept = new Department
            {
                Name = "Math",
                Budget = 50000,
                StartDate = DateTime.Parse("2020-01-01")
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course
            {
                CourseID = 1001,
                Title = "Algebra",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            context.Courses.Add(course);
            context.SaveChanges();

            var retrieved = context.Courses
                .Include(c => c.Department)
                .Single();
            Assert.Equal("Algebra", retrieved.Title);
            Assert.Equal("Math", retrieved.Department!.Name);
        }

        [Fact]
        public void CanAddEnrollment()
        {
            using var context = TestHelper.CreateSeededContext();

            var enrollment = new Enrollment
            {
                StudentID = 10,
                CourseID = 4022,
                Grade = Grade.B
            };
            context.Enrollments.Add(enrollment);
            context.SaveChanges();

            Assert.Equal(2, context.Enrollments.Count());
        }

        [Fact]
        public void CourseAssignment_HasCompositeKey()
        {
            using var context = TestHelper.CreateSeededContext();

            var assignment = context.CourseAssignments.Find(1050, 1);
            Assert.NotNull(assignment);
        }

        [Fact]
        public void OfficeAssignment_UsesInstructorIdAsKey()
        {
            using var context = TestHelper.CreateSeededContext();

            var office = context.OfficeAssignments.Find(2);
            Assert.NotNull(office);
            Assert.Equal("Smith 17", office!.Location);
        }

        [Fact]
        public void Students_InheritFromPerson()
        {
            using var context = TestHelper.CreateSeededContext();

            var people = context.People.ToList();
            Assert.NotEmpty(people);
            Assert.Contains(people, p => p is Student);
            Assert.Contains(people, p => p is Instructor);
        }

        [Fact]
        public void Notifications_CanBeAdded()
        {
            using var context = TestHelper.CreateContext();

            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test notification",
                CreatedAt = DateTime.Now,
                CreatedBy = "System",
                IsRead = false
            };
            context.Notifications.Add(notification);
            context.SaveChanges();

            Assert.Single(context.Notifications);
        }
    }
}

