using System;
using System.Collections.Generic;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class ModelTests
    {
        [Fact]
        public void Person_FullName_ReturnsCombinedName()
        {
            var student = new Student
            {
                FirstMidName = "John",
                LastName = "Doe"
            };

            Assert.Equal("Doe, John", student.FullName);
        }

        [Fact]
        public void Student_InheritsFromPerson()
        {
            var student = new Student();
            Assert.IsAssignableFrom<Person>(student);
        }

        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            var instructor = new Instructor();
            Assert.IsAssignableFrom<Person>(instructor);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_TrueWhenNotEmpty()
        {
            var model = new ErrorViewModel { RequestId = "abc123" };
            Assert.True(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_FalseWhenEmpty()
        {
            var model = new ErrorViewModel { RequestId = "" };
            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_FalseWhenNull()
        {
            var model = new ErrorViewModel { RequestId = null };
            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void Course_Properties_CanBeSet()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Test",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/images/test.jpg"
            };

            Assert.Equal(1, course.CourseID);
            Assert.Equal("Test", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
            Assert.Equal("/images/test.jpg", course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Department_Properties_CanBeSet()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Test",
                Budget = 50000,
                StartDate = DateTime.Parse("2020-01-01"),
                InstructorID = 1
            };

            Assert.Equal(1, dept.DepartmentID);
            Assert.Equal("Test", dept.Name);
            Assert.Equal(50000, dept.Budget);
            Assert.Null(dept.RowVersion);
        }

        [Fact]
        public void Enrollment_GradeCanBeNull()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1,
                StudentID = 1,
                Grade = null
            };

            Assert.Null(enrollment.Grade);
        }

        [Fact]
        public void Enrollment_GradeEnum_HasExpectedValues()
        {
            Assert.Equal(0, (int)Grade.A);
            Assert.Equal(1, (int)Grade.B);
            Assert.Equal(2, (int)Grade.C);
            Assert.Equal(3, (int)Grade.D);
            Assert.Equal(4, (int)Grade.F);
        }

        [Fact]
        public void Notification_Properties_CanBeSet()
        {
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "Created",
                CreatedAt = now,
                CreatedBy = "Admin",
                IsRead = true,
                ReadAt = now
            };

            Assert.Equal(1, notification.Id);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.True(notification.IsRead);
            Assert.NotNull(notification.ReadAt);
        }

        [Fact]
        public void EntityOperation_HasExpectedValues()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }

        [Fact]
        public void CourseAssignment_Properties_CanBeSet()
        {
            var ca = new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 100
            };

            Assert.Equal(1, ca.InstructorID);
            Assert.Equal(100, ca.CourseID);
        }

        [Fact]
        public void OfficeAssignment_Properties_CanBeSet()
        {
            var oa = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Room 101"
            };

            Assert.Equal(1, oa.InstructorID);
            Assert.Equal("Room 101", oa.Location);
        }

        [Fact]
        public void AssignedCourseData_Properties()
        {
            var data = new AssignedCourseData
            {
                CourseID = 1,
                Title = "Math",
                Assigned = true
            };

            Assert.Equal(1, data.CourseID);
            Assert.Equal("Math", data.Title);
            Assert.True(data.Assigned);
        }

        [Fact]
        public void EnrollmentDateGroup_Properties()
        {
            var group = new EnrollmentDateGroup
            {
                EnrollmentDate = DateTime.Parse("2020-01-01"),
                StudentCount = 5
            };

            Assert.Equal(DateTime.Parse("2020-01-01"), group.EnrollmentDate);
            Assert.Equal(5, group.StudentCount);
        }

        [Fact]
        public void InstructorIndexData_Properties()
        {
            var data = new InstructorIndexData
            {
                Instructors = new List<Instructor>(),
                Courses = new List<Course>(),
                Enrollments = new List<Enrollment>()
            };

            Assert.NotNull(data.Instructors);
            Assert.NotNull(data.Courses);
            Assert.NotNull(data.Enrollments);
        }
    }
}

